/**
 * User notification preferences model.
 *
 * Controls which notifications a user receives and how they receive them.
 * Supports per-channel settings for email, SMS, and webhook channels.
 *
 * History: Originally email-only (Session 3). Extended to multi-channel
 * after SMS support was added (Session 8) and webhook already existed.
 */

import type { NotificationType } from './notification.js';

/**
 * Delivery frequency for any notification channel.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 */
export type NotificationFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/** @deprecated Use NotificationFrequency instead — kept for backward compatibility */
export type EmailFrequency = NotificationFrequency;

/**
 * Per-category subscription flags for notifications.
 * Each key maps to a NotificationType. Shared across all channels.
 */
export interface CategoryPreferences {
  orderConfirmations: boolean;
  orderStatusUpdates: boolean;
  welcomeMessages: boolean;
  accountUpdates: boolean;
}

/** @deprecated Use CategoryPreferences instead — kept for backward compatibility */
export type EmailCategoryPreferences = CategoryPreferences;

/**
 * Per-channel notification preferences. All channels share this shape.
 */
export interface ChannelNotificationPreferences {
  /** Master switch — when false, no notifications sent on this channel regardless of category settings */
  enabled: boolean;
  /** Delivery frequency */
  frequency: NotificationFrequency;
  /** Per-category opt-in/opt-out */
  categories: CategoryPreferences;
}

/** @deprecated Use ChannelNotificationPreferences instead — kept for backward compatibility */
export type EmailNotificationPreferences = ChannelNotificationPreferences;

/** SMS-specific preferences (same shape as other channels) */
export type SmsNotificationPreferences = ChannelNotificationPreferences;

/** Webhook-specific preferences (same shape as other channels) */
export type WebhookNotificationPreferences = ChannelNotificationPreferences;

/**
 * Complete user notification preferences record.
 */
export interface UserNotificationPreferences {
  /** Unique ID for this preferences record */
  id: string;
  /** The user these preferences belong to */
  userId: string;
  /** Email notification settings */
  email: ChannelNotificationPreferences;
  /** SMS notification settings */
  sms: ChannelNotificationPreferences;
  /** Webhook notification settings */
  webhook: ChannelNotificationPreferences;
  /** When preferences were last modified */
  updatedAt: Date;
}

/**
 * Maps NotificationType to the corresponding category key in CategoryPreferences.
 */
export const notificationTypeToCategory: Record<NotificationType, keyof CategoryPreferences> = {
  'order-confirmation': 'orderConfirmations',
  'order-status-update': 'orderStatusUpdates',
  'welcome': 'welcomeMessages',
  'account-updated': 'accountUpdates',
};

/** Default channel preferences — all enabled, immediate delivery. */
function createDefaultChannelPreferences(): ChannelNotificationPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categories: {
      orderConfirmations: true,
      orderStatusUpdates: true,
      welcomeMessages: true,
      accountUpdates: true,
    },
  };
}

/**
 * Default preferences for new users — all channels enabled, immediate delivery.
 */
export function createDefaultPreferences(userId: string, id: string): UserNotificationPreferences {
  return {
    id,
    userId,
    email: createDefaultChannelPreferences(),
    sms: createDefaultChannelPreferences(),
    webhook: createDefaultChannelPreferences(),
    updatedAt: new Date(),
  };
}

