  UserNotificationPreferences,
  NotificationFrequency,
  CategoryPreferences,
  ChannelNotificationPreferences,
} from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

/** Default channel preferences used when loading records that predate multi-channel support. */
const defaultChannelPrefs: ChannelNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  categories: {
    orderConfirmations: true,
    orderStatusUpdates: true,
    welcomeMessages: true,
    accountUpdates: true,
  },
};

export class PreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user_notification_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as NotificationFrequency,
        categories: JSON.parse(record['emailCategories'] as string) as CategoryPreferences,
      },
      sms: record['smsEnabled'] !== undefined
        ? {
            enabled: record['smsEnabled'] as boolean,
            frequency: record['smsFrequency'] as NotificationFrequency,
            categories: JSON.parse(record['smsCategories'] as string) as CategoryPreferences,
          }
        : { ...defaultChannelPrefs },
      webhook: record['webhookEnabled'] !== undefined
        ? {
            enabled: record['webhookEnabled'] as boolean,
            frequency: record['webhookFrequency'] as NotificationFrequency,
            categories: JSON.parse(record['webhookCategories'] as string) as CategoryPreferences,
          }
        : { ...defaultChannelPrefs },
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailCategories: JSON.stringify(entity.email.categories),
      smsEnabled: entity.sms.enabled,
      smsFrequency: entity.sms.frequency,
      smsCategories: JSON.stringify(entity.sms.categories),
      webhookEnabled: entity.webhook.enabled,
      webhookFrequency: entity.webhook.frequency,
      webhookCategories: JSON.stringify(entity.webhook.categories),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

