import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type {
  UserNotificationPreferences,
  ChannelNotificationPreferences,
} from '../models/user-preferences.js';
import { createDefaultPreferences, notificationTypeToCategory } from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import { Logger } from '../utils/logger.js';

/** Channels that have per-user preference support. */
const SUPPORTED_PREFERENCE_CHANNELS: ReadonlySet<NotificationChannel> = new Set(['email', 'sms', 'webhook']);

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Creates defaults if none exist.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`Creating default preferences for user: ${userId}`);
    const defaults = createDefaultPreferences(userId, generatePreferencesId());
    return this.repository.save(defaults);
  }

  /**
   * Update email notification preferences for a user.
   * Merges the provided updates with existing preferences.
   */
  updateEmailPreferences(
    userId: string,
    updates: Partial<ChannelNotificationPreferences>,
  ): UserNotificationPreferences {
    return this.updateChannelPreferences(userId, 'email', updates);
  }

  /**
   * Update SMS notification preferences for a user.
   * Merges the provided updates with existing preferences.
   */
  updateSmsPreferences(
    userId: string,
    updates: Partial<ChannelNotificationPreferences>,
  ): UserNotificationPreferences {
    return this.updateChannelPreferences(userId, 'sms', updates);
  }

  /**
   * Update webhook notification preferences for a user.
   * Merges the provided updates with existing preferences.
   */
  updateWebhookPreferences(
    userId: string,
    updates: Partial<ChannelNotificationPreferences>,
  ): UserNotificationPreferences {
    return this.updateChannelPreferences(userId, 'webhook', updates);
  }

  /**
   * Generic channel preference updater. Merges partial updates with existing channel prefs.
   */
  private updateChannelPreferences(
    userId: string,
    channel: 'email' | 'sms' | 'webhook',
    updates: Partial<ChannelNotificationPreferences>,
  ): UserNotificationPreferences {
    const current = this.getPreferences(userId);
    const existing = current[channel];
    const updated = { ...existing };

    if (updates.enabled !== undefined) {
      updated.enabled = updates.enabled;
    }
    if (updates.frequency !== undefined) {
      updated.frequency = updates.frequency;
    }
    if (updates.categories !== undefined) {
      updated.categories = { ...updated.categories, ...updates.categories };
    }

    return this.repository.update(current.id, {
      [channel]: updated,
      updatedAt: new Date(),
    });
  }

  /**
   * Check whether a notification should be sent to a user.
   * Returns true if the notification is allowed by the user's preferences.
   *
   * Channels with preference support (email, sms, webhook) are checked against
   * per-channel settings. Other channels (e.g. in-app) default to allowed.
   */
  isNotificationEnabled(
    userId: string,
    type: NotificationType,
    channel: NotificationChannel,
  ): boolean {
    if (!SUPPORTED_PREFERENCE_CHANNELS.has(channel)) {
      return true;
    }

    const prefs = this.getPreferences(userId);
    const channelPrefs = prefs[channel as 'email' | 'sms' | 'webhook'];

    if (!channelPrefs.enabled) {
      this.logger.info(`${channel} notifications disabled for user: ${userId}`);
      return false;
    }

    const categoryKey = notificationTypeToCategory[type];
    if (!channelPrefs.categories[categoryKey]) {
      this.logger.info(
        `Category "${categoryKey}" disabled on ${channel} for user: ${userId}`,
      );
      return false;
    }

    return true;
  }
}

