import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should create default preferences for new user', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories.orderConfirmations).toBe(true);
      expect(prefs.email.categories.orderStatusUpdates).toBe(true);
      expect(prefs.email.categories.welcomeMessages).toBe(true);
      expect(prefs.email.categories.accountUpdates).toBe(true);
    });

    it('should return existing preferences', () => {
      const first = service.getPreferences('user-1');
      const second = service.getPreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(first.userId).toBe(second.userId);
    });

    it('should generate sequential IDs for different users', () => {
      const prefs1 = service.getPreferences('user-1');
      const prefs2 = service.getPreferences('user-2');

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', () => {
      service.getPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.email.enabled).toBe(false);
      // Categories should remain unchanged
      expect(updated.email.categories.orderConfirmations).toBe(true);
    });

    it('should update frequency', () => {
      service.getPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'daily-digest',
      });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update individual categories', () => {
      service.getPreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        categories: { orderConfirmations: false, orderStatusUpdates: false, welcomeMessages: true, accountUpdates: true },
      });

      expect(updated.email.categories.orderConfirmations).toBe(false);
      expect(updated.email.categories.orderStatusUpdates).toBe(false);
      expect(updated.email.categories.welcomeMessages).toBe(true);
      expect(updated.email.categories.accountUpdates).toBe(true);
    });

    it('should persist updates across reads', () => {
      service.getPreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      const reread = service.getPreferences('user-1');
      expect(reread.email.enabled).toBe(false);
    });

    it('should create defaults if user has no preferences yet', () => {
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly-digest',
      });

      expect(updated.userId).toBe('user-1');
      expect(updated.email.frequency).toBe('weekly-digest');
      expect(updated.email.enabled).toBe(true);
    });
  });

  describe('isNotificationEnabled', () => {
    it('should return true for default preferences', () => {
      expect(service.isNotificationEnabled('user-1', 'order-confirmation', 'email')).toBe(true);
      expect(service.isNotificationEnabled('user-1', 'order-status-update', 'email')).toBe(true);
      expect(service.isNotificationEnabled('user-1', 'welcome', 'email')).toBe(true);
      expect(service.isNotificationEnabled('user-1', 'account-updated', 'email')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.isNotificationEnabled('user-1', 'order-confirmation', 'email')).toBe(false);
      expect(service.isNotificationEnabled('user-1', 'welcome', 'email')).toBe(false);
    });

    it('should return false for disabled category', () => {
      service.updateEmailPreferences('user-1', {
        categories: { orderConfirmations: false, orderStatusUpdates: true, welcomeMessages: true, accountUpdates: true },
      });

      expect(service.isNotificationEnabled('user-1', 'order-confirmation', 'email')).toBe(false);
      expect(service.isNotificationEnabled('user-1', 'order-status-update', 'email')).toBe(true);
    });

    it('should return true for unknown channels (default allow)', () => {
      expect(service.isNotificationEnabled('user-1', 'welcome', 'webhook')).toBe(true);
    });
  });
});

